"use client";

import { useState } from "react";

export default function AddPlanPage() {
  const [programId, setProgramId] = useState("");
  const [catalogYear, setCatalogYear] = useState("");
  const [name, setName] = useState("");

  
  function onSubmit(e: React.FormEvent) {
    e.preventDefault();
    alert(
      `(stub) would create plan:\n` +
        JSON.stringify(
          { program_id: programId, catalog_year: catalogYear, name },
          null,
          2
        )
    );
  }

  const label = { display: "block", fontSize: 14, marginBottom: 6, color: "#333" } as const;
  const input = {
    width: "100%",
    border: "1px solid #e5e5e5",
    borderRadius: 8,
    padding: "10px 12px",
  } as const;

  return (
    <section style={{ maxWidth: 560 }}>
      <h1 style={{ fontSize: "1.5rem", fontWeight: 600, marginBottom: 16 }}>
        Create a New Plan
      </h1>

      <form
        onSubmit={onSubmit}
        style={{
          border: "1px solid #e5e5e5",
          borderRadius: 12,
          padding: 16,
          background: "#fff",
          boxShadow: "0 1px 2px rgba(0,0,0,0.04)",
        }}
      >
        <label style={label}>
          Program
          <input
            placeholder="e.g., CE-BS"
            value={programId}
            onChange={(e) => setProgramId(e.target.value)}
            style={input}
          />
        </label>

        <label style={label}>
          Catalog Year
          <input
            placeholder="e.g., 2025-2026"
            value={catalogYear}
            onChange={(e) => setCatalogYear(e.target.value)}
            style={input}
          />
        </label>

        <label style={label}>
          Plan Name (optional)
          <input
            placeholder="My Plan"
            value={name}
            onChange={(e) => setName(e.target.value)}
            style={input}
          />
        </label>

        <button
          type="submit"
          style={{
            marginTop: 12,
            width: "100%",
            borderRadius: 8,
            padding: "10px 12px",
            background: "#2563eb",
            color: "#fff",
            border: "none",
            cursor: "pointer",
          }}
        >
          Create Plan
        </button>
      </form>
    </section>
  );
}
